// ═══════════════════════════════════════════════════════
//  BufaSprites.ts — Efeito visual da Bufa Celeste (3 frames)
//
//  A Bufa é um peido tóxico de cores verdes e azul celeste.
//  A fumaça toma conta do corpo e se espalha pros dois lados.
//
//  Sequência:
//  INICIO → gás começando a formar por trás/baixo
//  MEIO   → nuvem enorme engolindo o corpo, espalhando pros lados
//  FIM    → nuvem expandida além do corpo, ficando transparente
//
//  Renderizado SOBRE o sprite do Wallaçaum (zIndex separado)
//  Tamanho recomendado: 140x140px (maior que o personagem)
//
//  Paleta: verde tóxico #2ECC71, #1A9E4A
//          azul celeste #87CEEB, #00CED1, #48D1CC
// ═══════════════════════════════════════════════════════

export const BUFA_SPRITES = {
  INICIO: "data:image/png;base64,",  // Frame 1: corpo tensionando, fio de gás verde/azul surgindo por trás
  MEIO:   "data:image/png;base64,",  // Frame 2: explosão, nuvem verde+azul engolindo corpo, espalhando ←→
  FIM:    "data:image/png;base64,",  // Frame 3: nuvem expandida, transparente nas pontas, dissipando
};
